import { customFetch } from './base';
import type { CronListResponse, CronSummary, CronToggleResponse, SystemStatus, BudgetStatus, CodeFinding, OmniusUser, CreateUserRequest, CreateUserResponse, AuditLogEntry } from './admin-types';

// Crons (Gilbertus API)
export async function getCrons(params?: { user?: string; category?: string }, signal?: AbortSignal): Promise<CronListResponse> {
  const queryParams: Record<string, string> = {};
  if (params?.user) queryParams.user = params.user;
  if (params?.category) queryParams.category = params.category;
  return customFetch<CronListResponse>({ url: '/crons', method: 'GET', params: Object.keys(queryParams).length ? queryParams : undefined, signal });
}

export async function getCronSummary(signal?: AbortSignal): Promise<CronSummary> {
  return customFetch<CronSummary>({ url: '/crons/summary', method: 'GET', signal });
}

export async function enableCron(jobName: string, user: string = 'sebastian'): Promise<CronToggleResponse> {
  return customFetch<CronToggleResponse>({ url: `/crons/${encodeURIComponent(jobName)}/enable`, method: 'POST', params: { user } });
}

export async function disableCron(jobName: string, user: string = 'sebastian'): Promise<CronToggleResponse> {
  return customFetch<CronToggleResponse>({ url: `/crons/${encodeURIComponent(jobName)}/disable`, method: 'POST', params: { user } });
}

// System Status (Gilbertus API)
export async function getSystemStatus(signal?: AbortSignal): Promise<SystemStatus> {
  return customFetch<SystemStatus>({ url: '/status', method: 'GET', signal });
}

// Costs (Gilbertus API — reuse getCostBudget from finance.ts)
