// Code Findings (Gilbertus API)
export async function getCodeFindings(signal?: AbortSignal): Promise<CodeFinding[]> {
  return customFetch<CodeFinding[]>({ url: '/code-fixes/manual-queue', method: 'GET', signal });
}

// Users (Omnius API)
export async function getOmniusUsers(signal?: AbortSignal): Promise<OmniusUser[]> {
  return customFetch<OmniusUser[]>({ url: '/api/v1/admin/users', method: 'GET', signal });
}

export async function createOmniusUser(data: CreateUserRequest): Promise<CreateUserResponse> {
  return customFetch<CreateUserResponse>({ url: '/api/v1/admin/users', method: 'POST', data });
