## File 3: `apps/web/lib/hooks/use-omnius-bridge.ts`
```typescript
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getTenantStatus, getOperatorTasks, createOperatorTask, updateOperatorTask, getTenantAuditLog, getTenantConfig, pushTenantConfig, triggerTenantSync } from '@gilbertus/api-client';
import type { OmniusTenant, CreateTaskRequest, UpdateTaskRequest } from '@gilbertus/api-client';

export function useTenantStatus(tenant: OmniusTenant) {
  return useQuery({
    queryKey: ['tenant-status', tenant],
    queryFn: () => getTenantStatus(tenant),
    staleTime: 30_000,
  });
}

// Helper: fetch both tenants in parallel
export function useBothTenantsStatus() {
  const reh = useTenantStatus('reh');
  const ref = useTenantStatus('ref');
  return { reh, ref, isLoading: reh.isLoading || ref.isLoading };
}

export function useOperatorTasks(tenant: OmniusTenant) {
  return useQuery({
    queryKey: ['operator-tasks', tenant],
    queryFn: () => getOperatorTasks(tenant),
    staleTime: 30_000,
  });
}

export function useCreateOperatorTask(tenant: OmniusTenant) {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (data: CreateTaskRequest) => createOperatorTask(tenant, data),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['operator-tasks', tenant] }),
  });
}

export function useUpdateOperatorTask(tenant: OmniusTenant) {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (params: { taskId: number; data: UpdateTaskRequest }) => updateOperatorTask(tenant, params.taskId, params.data),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['operator-tasks', tenant] }),
  });
}

export function useTenantAuditLog(tenant: OmniusTenant) {
  return useQuery({
    queryKey: ['tenant-audit', tenant],
    queryFn: () => getTenantAuditLog(tenant),
    staleTime: 30_000,
  });
}

export function useTenantConfig(tenant: OmniusTenant) {
  return useQuery({
    queryKey: ['tenant-config', tenant],
    queryFn: () => getTenantConfig(tenant),
    staleTime: 60_000,
  });
}

export function usePushTenantConfig(tenant: OmniusTenant) {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (data: { key: string; value: any }) => pushTenantConfig(tenant, data.key, data.value),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['tenant-config', tenant] }),
  });
}

export function useTriggerSync(tenant: OmniusTenant) {
  return useMutation({
    mutationFn: (source: string) => triggerTenantSync(tenant, source),
  });
}
```

