```tsx
'use client';
import { useRole } from '@gilbertus/rbac';
import { RbacGate } from '@gilbertus/ui';
import { useAdminStore } from '@/lib/stores/admin-store';
import { useBothTenantsStatus, useOperatorTasks, useCreateOperatorTask, useUpdateOperatorTask, useTenantAuditLog, useTenantConfig, usePushTenantConfig, useTriggerSync } from '@/lib/hooks/use-omnius-bridge';
import { TenantOverview, OperatorTasks, CrossTenantAudit, ConfigPush, SyncTrigger } from '@gilbertus/ui';

export default function OmniusBridgePage() {
  return (
    <RbacGate roles={['gilbertus_admin']} fallback={<p>Brak dostępu</p>}>
      <OmniusBridgeContent />
    </RbacGate>
  );
}

function OmniusBridgeContent() {
  const store = useAdminStore();
  const { omniusActiveTab: activeTab, setOmniusActiveTab: setActiveTab, omniusActiveTenant: tenant, setOmniusActiveTenant: setTenant } = store;

  // Overview
  const tenants = useBothTenantsStatus();

  // Tasks
  const tasks = useOperatorTasks(tenant);
  const createTask = useCreateOperatorTask(tenant);
  const updateTask = useUpdateOperatorTask(tenant);

  // Audit
  const audit = useTenantAuditLog(tenant);

  // Config
  const config = useTenantConfig(tenant);
  const pushConfig = usePushTenantConfig(tenant);

  // Sync
  const triggerSync = useTriggerSync(tenant);

  const tabs = [
    { id: 'overview', label: 'Przegląd' },
    { id: 'tasks', label: 'Zadania' },
    { id: 'audit', label: 'Audit' },
    { id: 'config', label: 'Konfiguracja' },
    { id: 'sync', label: 'Synchronizacja' },
  ];

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">Omnius Bridge</h1>
      {/* Tab bar */}
      <div className="flex gap-1 bg-[var(--surface)] rounded-lg p-1">
        {tabs.map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id)} className={...tab styles}>{t.label}</button>
        ))}
      </div>
      {/* Content */}
      {activeTab === 'overview' && <TenantOverview reh={tenants.reh} ref={tenants.ref} />}
      {activeTab === 'tasks' && <OperatorTasks activeTenant={tenant} onTenantChange={setTenant} tasks={tasks.data ?? []} isLoading={tasks.isLoading} onCreate={(d) => createTask.mutate(d)} isCreating={createTask.isPending} onUpdateStatus={(id, d) => updateTask.mutate({ taskId: id, data: d })} />}
      {activeTab === 'audit' && <CrossTenantAudit activeTenant={tenant} onTenantChange={setTenant} entries={audit.data ?? []} isLoading={audit.isLoading} />}
      {activeTab === 'config' && <ConfigPush activeTenant={tenant} onTenantChange={setTenant} config={config.data ?? []} isLoading={config.isLoading} onPush={(k, v) => pushConfig.mutate({ key: k, value: v })} isPushing={pushConfig.isPending} />}
      {activeTab === 'sync' && <SyncTrigger onSync={(t, s) => triggerSync.mutate(s)} isSyncing={triggerSync.isPending} />}
    </div>
  );
}
```
